import numpy as np

def select_next_node(current_node, destination_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return destination_node
    if len(unvisited_nodes) == 1:
        return unvisited_nodes[0]

    # 1. 快速聚类划分区域（基于距离阈值）
    sub_dist = distance_matrix[np.ix_(unvisited_nodes, unvisited_nodes)]
    avg_dist = np.mean(sub_dist)
    threshold = avg_dist * 1.5
    clusters = []
    assigned = np.zeros(len(unvisited_nodes), dtype=bool)
    for i in range(len(unvisited_nodes)):
        if not assigned[i]:
            cluster = [i]
            assigned[i] = True
            for j in range(i+1, len(unvisited_nodes)):
                if not assigned[j] and distance_matrix[unvisited_nodes[i], unvisited_nodes[j]] < threshold:
                    cluster.append(j)
                    assigned[j] = True
            clusters.append(cluster)

    # 2. 确定当前区域：包含当前节点最近邻未访问节点的区域
    if len(unvisited_nodes) > 0:
        dists_to_current = distance_matrix[current_node, unvisited_nodes]
        nearest_idx = np.argmin(dists_to_current)
        current_region_idx = None
        for idx, cluster in enumerate(clusters):
            if nearest_idx in cluster:
                current_region_idx = idx
                break
        # 如果当前节点最近邻不在任何区域（理论上不会），则选第一个区域
        if current_region_idx is None:
            current_region_idx = 0
    else:
        current_region_idx = 0

    # 3. 方向一致性评估：计算当前节点到剩余未访问节点平均方向向量
    # 由于无坐标，用距离向量近似：取当前节点到每个未访问节点的方向为单位向量（无法直接获得），
    # 改用角度估计：计算候选节点与“当前节点到其他未访问节点平均距离向量”的余弦相似度替代。
    # 简化实现：用距离差构造伪方向向量
    if len(unvisited_nodes) > 1:
        # 构造伪方向向量：对每个候选节点，计算其到其他未访问节点的平均距离差
        direction_scores = np.zeros(len(unvisited_nodes))
        for i, node in enumerate(unvisited_nodes):
            other_nodes = np.delete(unvisited_nodes, i)
            # 当前节点到候选节点的距离
            d_current_to_candidate = distance_matrix[current_node, node]
            # 候选节点到其他未访问节点的平均距离
            avg_dist_to_others = np.mean(distance_matrix[node, other_nodes])
            # 方向得分：如果候选节点离当前近且离其他节点也近，则方向一致（得分高）
            # 用距离和的倒数作为得分，鼓励选择“枢纽性”节点
            direction_scores[i] = 1.0 / (d_current_to_candidate + 0.5 * avg_dist_to_others)
    else:
        direction_scores = np.ones(len(unvisited_nodes))

    # 4. 区域优先级：当前区域内节点优先级高，区域外节点优先级低
    region_priority = np.zeros(len(unvisited_nodes))
    for idx, cluster in enumerate(clusters):
        for node_idx in cluster:
            if idx == current_region_idx:
                region_priority[node_idx] = 1.0
            else:
                region_priority[node_idx] = 0.3  # 区域外惩罚

    # 5. 连通性触发式终点选择
    dest_idx = None
    if destination_node in unvisited_nodes:
        dest_idx = np.where(unvisited_nodes == destination_node)[0][0]
        # 判断终点所属区域
        dest_region_idx = None
        for idx, cluster in enumerate(clusters):
            if dest_idx in cluster:
                dest_region_idx = idx
                break
        # 触发条件：终点区域与当前区域相邻（区域数<=2）或剩余区域数少（<=2）
        if dest_region_idx is not None:
            if len(clusters) <= 2:
                # 提升终点优先级
                region_priority[dest_idx] = 1.5
            elif dest_region_idx == current_region_idx:
                # 终点在当前区域内，正常处理
                pass
            else:
                # 终点在其他区域，适度降低优先级
                region_priority[dest_idx] = 0.2

    # 6. 距离成本归一化
    dist_costs = distance_matrix[current_node, unvisited_nodes]
    if np.max(dist_costs) > 0:
        dist_norm = dist_costs / np.max(dist_costs)
    else:
        dist_norm = np.zeros_like(dist_costs)

    # 7. 综合得分：距离成本负向 + 方向得分正向 + 区域优先级正向
    if np.max(direction_scores) > 0:
        dir_norm = direction_scores / np.max(direction_scores)
    else:
        dir_norm = np.ones_like(direction_scores)

    scores = -0.6 * dist_norm + 0.3 * dir_norm + 0.4 * region_priority

    # 8. 选择得分最高的节点
    best_idx = np.argmax(scores)
    next_node = unvisited_nodes[best_idx]
    return next_node
